let atendimentos = [];
let logsAlteracoes = [];
const horariosAtendimento = [
  "08:00","08:30","09:00","09:30","10:00","10:30","11:00","11:30",
  "13:00","13:30","14:00","14:30","15:00","15:30","16:00","16:30"
];
let filtroDataModo = "todos";

async function salvarAtendimentosFirebase(){
  try{
    await DOC_ATENDIMENTOS.set({
      itens: atendimentos,
      logs: logsAlteracoes,
      atualizadoEm: new Date().toISOString()
    }, { merge: true });
  }catch(e){
    console.error(e);
    mostrarErro("Erro ao salvar no Firebase.");
    throw e;
  }
}

async function carregarAtendimentosFirebase(){
  try{
    const snap = await DOC_ATENDIMENTOS.get();
    if(snap.exists){
      const dados = snap.data() || {};
      atendimentos = Array.isArray(dados.itens) ? dados.itens : [];
      logsAlteracoes = Array.isArray(dados.logs) ? dados.logs : [];
    } else {
      atendimentos = [];
      logsAlteracoes = [];
      await DOC_ATENDIMENTOS.set({ itens: [], logs: [], criadoEm: new Date().toISOString() }, { merge: true });
    }
  }catch(e){
    console.error(e);
    atendimentos = [];
    logsAlteracoes = [];
    mostrarErro("Não foi possível carregar os dados do Firebase.");
  }
}

