/* ===== PACIENTES INTEGRADO: criar, editar, excluir e impedir duplicados ===== */
function mostrarSucesso(msg){ mostrarToast(msg, "sucesso"); }

function normalizarPacienteDuplicidade(valor){
  return String(valor || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim()
    .toUpperCase();
}

function prepararNomePaciente(valor){
  return String(valor || "")
    .replace(/\s+/g, " ")
    .trim()
    .toUpperCase()
    .slice(0, 220);
}

function pacienteExisteNaMesmaPasta(pasta, nome, ignorarPasta=null, ignorarIndex=null){
  const pastaNormalizada = normalizarPasta(pasta);
  const nomeNormalizado = normalizarPacienteDuplicidade(nome);
  const lista = Array.isArray(cadastros[pastaNormalizada]) ? cadastros[pastaNormalizada] : [];

  return lista.some((nomeAtual, indexAtual) => {
    const mesmoRegistroIgnorado = String(ignorarPasta) === String(pastaNormalizada) && Number(ignorarIndex) === Number(indexAtual);
    if(mesmoRegistroIgnorado) return false;
    return normalizarPacienteDuplicidade(nomeAtual) === nomeNormalizado;
  });
}

function contarPacientes(){
  return Object.values(cadastros).reduce((total, nomes) => total + (Array.isArray(nomes) ? nomes.length : 0), 0);
}

function salvarAtendimentosFirebase(){
  return DOC_ATENDIMENTOS.set({
    itens: atendimentos,
    logs: logsAlteracoes,
    cadastros: cadastros,
    senhas: senhas,
    atualizadoEm: new Date().toISOString()
  }, { merge: true }).catch(e => {
    console.error(e);
    mostrarErro("Erro ao salvar no Firebase.");
    throw e;
  });
}

async function salvarCadastrosFirebase(){
  const cadastrosLimpos = {};

  Object.entries(cadastros).forEach(([pasta, nomes]) => {
    const pastaLimpa = normalizarPasta(pasta);
    if(!pastaLimpa) return;

    const listaLimpa = Array.isArray(nomes)
      ? nomes.map(prepararNomePaciente).filter(Boolean)
      : [];

    if(listaLimpa.length > 0){
      cadastrosLimpos[pastaLimpa] = listaLimpa;
    }
  });

  Object.keys(cadastros).forEach(pasta => delete cadastros[pasta]);
  Object.assign(cadastros, cadastrosLimpos);

  const payload = {
    cadastros: cadastrosLimpos,
    atualizadoEm: new Date().toISOString()
  };

  try{
    // update substitui o campo cadastros inteiro. Assim, pastas apagadas não voltam ao dar F5.
    await DOC_ATENDIMENTOS.update(payload);
  }catch(e){
    // Se o documento ainda não existir, cria normalmente.
    if(e && (e.code === "not-found" || String(e.message || "").toLowerCase().includes("no document"))){
      await DOC_ATENDIMENTOS.set(payload, { merge: true });
      return;
    }
    throw e;
  }
}

async function carregarAtendimentosFirebase(){
  try{
    const snap = await DOC_ATENDIMENTOS.get();
    if(snap.exists){
      const dados = snap.data() || {};
      atendimentos = Array.isArray(dados.itens) ? dados.itens : [];
      logsAlteracoes = Array.isArray(dados.logs) ? dados.logs : [];

      if(dados.senhas && typeof dados.senhas === "object"){
        senhas = { ...senhasPadrao };
        Object.keys(usuarios).forEach(login => {
          if(typeof dados.senhas[login] === "string" && dados.senhas[login].length > 0){
            senhas[login] = dados.senhas[login];
          }
        });
        senhasCarregadasFirebase = true;
      } else {
        await salvarSenhasFirebase(false);
      }

      if(dados.cadastros && typeof dados.cadastros === "object"){
        Object.keys(cadastros).forEach(pasta => delete cadastros[pasta]);
        Object.entries(dados.cadastros).forEach(([pasta, nomes]) => {
          const pastaLimpa = normalizarPasta(pasta);
          if(!pastaLimpa) return;
          cadastros[pastaLimpa] = Array.isArray(nomes) ? nomes.map(prepararNomePaciente).filter(Boolean) : [];
        });
      } else {
        await salvarCadastrosFirebase();
      }
    } else {
      atendimentos = [];
      logsAlteracoes = [];
      await DOC_ATENDIMENTOS.set({
        itens: [],
        logs: [],
        cadastros: cadastros,
        senhas: senhas,
        criadoEm: new Date().toISOString()
      }, { merge: true });
    }
  }catch(e){
    console.error(e);
    atendimentos = [];
    logsAlteracoes = [];
    mostrarErro("Não foi possível carregar os dados do Firebase.");
  }
}

function montarCardPaciente(pasta, nome, index){
  const pastaHTML = escapeHTML(pasta);
  const nomeHTML = escapeHTML(nome);
  const idMenu = `menuPaciente_${pasta}_${index}`;

  return `
    <div class="paciente-card" data-paciente-card data-busca="${nomeHTML} ${pastaHTML}">
      <div class="paciente-menu-wrap">
        <button type="button" class="btn-menu-paciente" onclick="alternarMenuPaciente(event,'${pastaHTML}',${index})">⋮</button>
        <div class="menu-paciente" id="${idMenu}">
          <button type="button" onclick="event.stopPropagation(); editarPaciente('${pastaHTML}',${index})">✏️ Editar</button>
          <button type="button" class="danger" onclick="event.stopPropagation(); excluirPaciente('${pastaHTML}',${index})">🗑️ Excluir</button>
        </div>
      </div>
      <strong>${nomeHTML}</strong>
      <span>📁 Pasta ${pastaHTML}</span>
    </div>
  `;
}

function abrirTelaPacientes(){
  setTelaAtiva("pacientes");
  mostrarBlocosAgendamento(false);

  const totalPastas = Object.keys(cadastros).length;
  const totalNomes = contarPacientes();
  let cards = "";

  Object.entries(cadastros)
    .sort((a,b) => Number(a[0]) - Number(b[0]))
    .forEach(([pasta, nomes]) => {
      (Array.isArray(nomes) ? nomes : []).forEach((nome, index) => {
        cards += montarCardPaciente(pasta, nome, index);
      });
    });

  lista.innerHTML = `
    <div class="pagina-titulo">Pastas</div>
    <div class="pagina-sub">Cadastre, edite, exclua e busque pacientes por nome ou nº da pasta.</div>

    <div class="search-card pacientes-form-card">
      <div class="pacientes-form-grid">
        <div>
          <label>Nº da pasta</label>
          <input id="pacienteNovaPasta" inputmode="numeric" placeholder="Ex: 954">
        </div>
        <div>
          <label>Nome do paciente</label>
          <input id="pacienteNovoNome" placeholder="Digite o nome completo">
        </div>
        <button type="button" onclick="criarNovoPaciente()">Adicionar paciente</button>
      </div>
    </div>

    <div class="search-card" style="margin-bottom:14px">
      <h3>BUSCAR PACIENTE</h3>
      <div class="search-box">
        <span>🔍</span>
        <input id="buscaPacientes" placeholder="Buscar por nome ou nº" oninput="filtrarPacientes()">
      </div>
    </div>

    <div class="pagina-sub">${totalNomes} nomes cadastrados em ${totalPastas} pastas.</div>
    <div id="listaPacientes" class="pacientes-grid">
      ${cards || `<div class="paciente-card"><strong>Nenhum paciente cadastrado.</strong></div>`}
    </div>
  `;
}

function filtrarPacientes(){
  const termo = normalizarBusca(document.getElementById("buscaPacientes")?.value || "");
  document.querySelectorAll("[data-paciente-card]").forEach(card => {
    const texto = normalizarBusca(card.dataset.busca || card.innerText || "");
    card.style.display = texto.includes(termo) ? "block" : "none";
  });
}

function alternarMenuPaciente(event, pasta, index){
  event.stopPropagation();
  const idAtual = `menuPaciente_${pasta}_${index}`;
  document.querySelectorAll(".menu-paciente").forEach(menu => {
    if(menu.id !== idAtual) menu.classList.remove("show");
  });
  const menu = document.getElementById(idAtual);
  if(menu) menu.classList.toggle("show");
}

document.addEventListener("click", () => {
  fecharMenusPaciente();
});

async function criarNovoPaciente(){
  const inputPasta = document.getElementById("pacienteNovaPasta");
  const inputNome = document.getElementById("pacienteNovoNome");
  const pastaNova = normalizarPasta(inputPasta?.value || "");
  const nomeNovo = prepararNomePaciente(inputNome?.value || "");

  if(!pastaNova){
    mostrarErro("Digite o número da pasta.");
    return;
  }
  if(!nomeNovo){
    mostrarErro("Digite o nome do paciente.");
    return;
  }
  if(pacienteExisteNaMesmaPasta(pastaNova, nomeNovo)){
    mostrarToast("Esse paciente já está cadastrado nessa pasta.", "erro");
    return;
  }

  if(!Array.isArray(cadastros[pastaNova])) cadastros[pastaNova] = [];
  cadastros[pastaNova].push(nomeNovo);

  try{
    await salvarCadastrosFirebase();
    abrirTelaPacientes();
    mostrarSucesso("Paciente adicionado com sucesso.");
  }catch(e){
    mostrarErro("Não foi possível salvar o paciente.");
  }
}

function garantirModalEdicaoPaciente(){
  let modal = document.getElementById("modalEditarPaciente");
  if(modal) return modal;

  modal = document.createElement("div");
  modal.id = "modalEditarPaciente";
  modal.className = "modal-fundo animado";
  modal.innerHTML = `
    <div class="modal-box" onclick="event.stopPropagation()">
      <h3>Editar paciente</h3>
      <p>Altere o número da pasta ou o nome do paciente.</p>
      <input type="hidden" id="editPacientePastaOriginal">
      <input type="hidden" id="editPacienteIndexOriginal">
      <label style="font-size:13px;font-weight:900;color:#64748b">Nº da pasta</label>
      <input id="editPacientePasta" inputmode="numeric" placeholder="Nº da pasta">
      <label style="font-size:13px;font-weight:900;color:#64748b;margin-top:10px;display:block">Nome do paciente</label>
      <input id="editPacienteNome" placeholder="Nome do paciente">
      <div class="modal-acoes" style="margin-top:16px">
        <button type="button" class="modal-cancelar" onclick="fecharModalEdicaoPaciente()">Cancelar</button>
        <button type="button" class="modal-confirmar" style="background:#166534" onclick="salvarEdicaoPacienteModal()">Salvar alterações</button>
      </div>
    </div>
  `;
  modal.addEventListener("click", fecharModalEdicaoPaciente);
  document.body.appendChild(modal);
  return modal;
}

function abrirModalEdicaoPaciente(pastaAntiga, index){
  fecharMenusPaciente();

  const pastaOriginal = normalizarPasta(pastaAntiga);
  const listaPacientes = cadastros[pastaOriginal];

  if(!Array.isArray(listaPacientes) || !listaPacientes[index]){
    mostrarErro("Paciente não encontrado.");
    return;
  }

  const modal = garantirModalEdicaoPaciente();
  document.getElementById("editPacientePastaOriginal").value = pastaOriginal;
  document.getElementById("editPacienteIndexOriginal").value = String(index);
  document.getElementById("editPacientePasta").value = pastaOriginal;
  document.getElementById("editPacienteNome").value = listaPacientes[index];
  modal.classList.add("show");

  setTimeout(() => {
    const campoNome = document.getElementById("editPacienteNome");
    if(campoNome){
      campoNome.focus();
      campoNome.select();
    }
  }, 50);
}

function fecharModalEdicaoPaciente(){
  const modal = document.getElementById("modalEditarPaciente");
  if(modal) modal.classList.remove("show");
}

async function salvarEdicaoPacienteModal(){
  const pastaOriginal = normalizarPasta(document.getElementById("editPacientePastaOriginal")?.value || "");
  const index = Number(document.getElementById("editPacienteIndexOriginal")?.value || -1);
  const novaPasta = normalizarPasta(document.getElementById("editPacientePasta")?.value || "");
  const novoNome = prepararNomePaciente(document.getElementById("editPacienteNome")?.value || "");
  const listaPacientes = cadastros[pastaOriginal];

  if(!Array.isArray(listaPacientes) || !listaPacientes[index]){
    mostrarErro("Paciente não encontrado.");
    return;
  }
  if(!novaPasta){
    mostrarErro("A pasta não pode ficar vazia.");
    return;
  }
  if(!novoNome){
    mostrarErro("O nome não pode ficar vazio.");
    return;
  }
  if(pacienteExisteNaMesmaPasta(novaPasta, novoNome, pastaOriginal, index)){
    mostrarToast("Esse paciente já está cadastrado nessa pasta.", "erro");
    return;
  }

  cadastros[pastaOriginal].splice(index, 1);
  if(cadastros[pastaOriginal].length === 0) delete cadastros[pastaOriginal];

  if(!Array.isArray(cadastros[novaPasta])) cadastros[novaPasta] = [];
  cadastros[novaPasta].push(novoNome);

  try{
    await salvarCadastrosFirebase();
    fecharModalEdicaoPaciente();
    abrirTelaPacientes();
    mostrarSucesso("Paciente editado com sucesso.");
  }catch(e){
    console.error(e);
    mostrarErro("Não foi possível editar o paciente.");
  }
}

async function editarPaciente(pastaAntiga, index){
  abrirModalEdicaoPaciente(pastaAntiga, index);
}

function fecharMenusPaciente(){
  document.querySelectorAll(".menu-paciente.show").forEach(menu => menu.classList.remove("show"));
}

function fecharModalComAnimacao(modal, aoFechar){
  if(!modal) return;
  modal.classList.add("saindo");
  setTimeout(() => {
    modal.classList.remove("show", "saindo");
    if(typeof aoFechar === "function") aoFechar();
  }, 190);
}

function garantirModalExclusaoPaciente(){
  let modal = document.getElementById("modalExcluirPaciente");
  if(modal) return modal;

  modal = document.createElement("div");
  modal.id = "modalExcluirPaciente";
  modal.className = "modal-fundo animado";
  modal.innerHTML = `
    <div class="modal-box modal-excluir-paciente" onclick="event.stopPropagation()">
      <div class="delete-icon-circle" id="iconeExcluirPaciente">×</div>
      <h3 id="tituloExcluirPaciente">Excluir paciente?</h3>
      <p id="textoExcluirPaciente">Essa ação removerá o paciente da lista de pastas.</p>
      <span class="paciente-alvo" id="alvoExcluirPaciente"></span>
      <div class="modal-acoes" id="acoesExcluirPaciente" style="margin-top:18px">
        <button type="button" class="btn-cancelar-exclusao" onclick="cancelarExclusaoPaciente()">Cancelar</button>
        <button type="button" class="btn-confirmar-exclusao" onclick="confirmarExclusaoPaciente()">Sim, excluir</button>
      </div>
    </div>
  `;
  modal.addEventListener("click", cancelarExclusaoPaciente);
  document.body.appendChild(modal);
  return modal;
}

let pacientePendenteExclusao = null;

function excluirPaciente(pasta, index){
  fecharMenusPaciente();

  const pastaOriginal = normalizarPasta(pasta);
  const listaPacientes = cadastros[pastaOriginal];

  if(!Array.isArray(listaPacientes) || !listaPacientes[index]){
    mostrarErro("Paciente não encontrado.");
    return;
  }

  pacientePendenteExclusao = {
    pasta: pastaOriginal,
    index: Number(index),
    nome: listaPacientes[index]
  };

  const modal = garantirModalExclusaoPaciente();
  const box = modal.querySelector(".modal-excluir-paciente");
  const icone = document.getElementById("iconeExcluirPaciente");
  const titulo = document.getElementById("tituloExcluirPaciente");
  const texto = document.getElementById("textoExcluirPaciente");
  const alvo = document.getElementById("alvoExcluirPaciente");
  const acoes = document.getElementById("acoesExcluirPaciente");

  if(box) box.classList.remove("cancelado", "excluido");
  if(icone){ icone.className = "delete-icon-circle"; icone.textContent = "×"; }
  if(titulo) titulo.textContent = "Excluir paciente?";
  if(texto) texto.textContent = "Confirme para remover este paciente da aba Pacientes.";
  if(alvo) alvo.textContent = `${pacientePendenteExclusao.nome} • Pasta ${pastaOriginal}`;
  if(acoes) acoes.style.display = "flex";

  modal.classList.remove("saindo");
  modal.classList.add("show");
}

function cancelarExclusaoPaciente(){
  const modal = document.getElementById("modalExcluirPaciente");
  if(!modal || !modal.classList.contains("show")) return;

  const box = modal.querySelector(".modal-excluir-paciente");
  const titulo = document.getElementById("tituloExcluirPaciente");
  const texto = document.getElementById("textoExcluirPaciente");
  const acoes = document.getElementById("acoesExcluirPaciente");

  if(box) box.classList.add("cancelado");
  if(titulo) titulo.textContent = "Exclusão cancelada";
  if(texto) texto.textContent = "Nenhuma alteração foi feita.";
  if(acoes) acoes.style.display = "none";

  setTimeout(() => {
    pacientePendenteExclusao = null;
    fecharModalComAnimacao(modal);
  }, 520);
}

async function confirmarExclusaoPaciente(){
  if(!pacientePendenteExclusao) return;

  const { pasta, index, nome } = pacientePendenteExclusao;
  const listaPacientes = cadastros[pasta];

  if(!Array.isArray(listaPacientes) || listaPacientes[index] !== nome){
    pacientePendenteExclusao = null;
    mostrarErro("Paciente não encontrado ou já foi alterado.");
    fecharModalComAnimacao(document.getElementById("modalExcluirPaciente"));
    return;
  }

  const modal = document.getElementById("modalExcluirPaciente");
  const box = modal?.querySelector(".modal-excluir-paciente");
  const icone = document.getElementById("iconeExcluirPaciente");
  const titulo = document.getElementById("tituloExcluirPaciente");
  const texto = document.getElementById("textoExcluirPaciente");
  const acoes = document.getElementById("acoesExcluirPaciente");

  if(acoes) acoes.style.display = "none";

  const cadastrosAntes = JSON.parse(JSON.stringify(cadastros));

  cadastros[pasta].splice(index, 1);
  if(cadastros[pasta].length === 0) delete cadastros[pasta];

  try{
    await salvarCadastrosFirebase();

    if(box) box.classList.add("excluido");
    if(icone){ icone.className = "delete-icon-circle concluido"; icone.textContent = "×"; }
    if(titulo) titulo.textContent = "Paciente excluído";
    if(texto) texto.textContent = "A ação foi concluída com sucesso.";

    const cards = Array.from(document.querySelectorAll("[data-paciente-card]"));
    const card = cards.find(c =>
      normalizarBusca(c.innerText || "").includes(normalizarBusca(nome)) &&
      normalizarBusca(c.innerText || "").includes(normalizarBusca(pasta))
    );
    if(card) card.classList.add("removendo");

    setTimeout(() => {
      pacientePendenteExclusao = null;
      fecharModalComAnimacao(modal, abrirTelaPacientes);
      mostrarSucesso("Paciente excluído com sucesso.");
    }, 650);
  }catch(e){
    console.error(e);

    Object.keys(cadastros).forEach(pastaAtual => delete cadastros[pastaAtual]);
    Object.assign(cadastros, cadastrosAntes);

    pacientePendenteExclusao = null;
    mostrarErro("Não foi possível excluir o paciente. Confira a conexão e tente novamente.");
    fecharModalComAnimacao(modal, abrirTelaPacientes);
  }
}


window.addEventListener("error", (event) => {
  console.error("Erro capturado no CAICAVV:", event.error || event.message);
  setTimeout(() => {
    const login = document.getElementById("loginDiv");
    const aplicativo = document.getElementById("app");
    const bodyVazio = document.body && document.body.innerText.trim().length < 5;

    if(login && (!aplicativo || aplicativo.style.display === "none") && !document.body.classList.contains("modo-app")){
      login.style.display = "flex";
    }

    if(bodyVazio){
      document.body.innerHTML = `
        <div style="min-height:100vh;display:grid;place-items:center;background:#eef4ff;font-family:Arial;padding:24px">
          <div style="max-width:520px;background:#fff;border:1px solid #d8e4fa;border-radius:18px;padding:24px;box-shadow:0 18px 45px rgba(15,23,42,.12);color:#071957">
            <h2 style="margin:0 0 10px">CAICAVV</h2>
            <p style="line-height:1.5;margin:0">O sistema encontrou um erro ao iniciar. Atualize a página com <b>Ctrl + F5</b>. Se continuar, confira se o arquivo <b>index.html</b> foi substituído corretamente no GitHub.</p>
          </div>
        </div>`;
    }
  }, 0);
});

window.addEventListener("DOMContentLoaded",()=>{
  try{
    aplicarTemaSalvo();

    renderOriginalCaicavv = typeof window.render === "function" ? window.render : null;
    window.render = function(){
      if(telaAtualCaicavv !== "agendamentos") return;
      return renderOriginalCaicavv ? renderOriginalCaicavv() : undefined;
    };

    const menuIcon = document.querySelector(".menu-icon");
    if(menuIcon) menuIcon.onclick = toggleMenuLateral;

    const login = document.getElementById("loginDiv");
    const aplicativo = document.getElementById("app");

    // Evita tela branca caso uma sessão antiga esteja quebrada no navegador.
    setTimeout(() => {
      const appVisivel = aplicativo && aplicativo.style.display !== "none";
      const loginVisivel = login && login.style.display !== "none";

      if(!appVisivel && !loginVisivel){
        document.body.classList.remove("modo-app");
        if(login) login.style.display = "flex";
      }
    }, 350);
  }catch(e){
    console.error(e);
    document.body.classList.remove("modo-app");
    const login = document.getElementById("loginDiv");
    const aplicativo = document.getElementById("app");
    if(aplicativo) aplicativo.style.display = "none";
    if(login) login.style.display = "flex";
  }
});



