let entradasManuaisCAICAVV = JSON.parse(localStorage.getItem("entradasManuaisCAICAVV") || "[]");

function salvarEntradasManuaisCAICAVV(){
  localStorage.setItem("entradasManuaisCAICAVV", JSON.stringify(entradasManuaisCAICAVV));
}

function todasEntradasCAICAVV(){
  return [...entradasBaseCAICAVV, ...entradasManuaisCAICAVV];
}

function podeAlterarEntradasCAICAVV(){
  const login = typeof loginAtual === "function" ? String(loginAtual() || "") : "";
  const u = typeof tecnicoLogado === "object" && tecnicoLogado ? tecnicoLogado : {};
  const texto = (login + " " + JSON.stringify(u)).toLowerCase();
  return texto.includes("mayara") || texto.includes("maiyara") || texto.includes("coordenacao") || texto.includes("coordenação") || texto.includes("adm.caicavv");
}

function entradaEscapeCAICAVV(valor){
  if(typeof escapeHTML === "function") return escapeHTML(valor);
  return String(valor ?? "").replace(/[&<>'"]/g, c => ({"&":"&amp;","<":"&lt;",">":"&gt;","'":"&#39;",'"':"&quot;"}[c]));
}

function entradaNormalizarCAICAVV(valor){
  return String(valor || "Não informado").trim() || "Não informado";
}

function entradaContarPorCAICAVV(lista, campo){
  const obj = {};
  lista.forEach(e => {
    const chave = entradaNormalizarCAICAVV(e[campo]);
    obj[chave] = (obj[chave] || 0) + 1;
  });
  return obj;
}

function entradaMaiorCAICAVV(obj){
  const itens = Object.entries(obj).sort((a,b)=>b[1]-a[1]);
  return itens.length ? itens[0][0] : "Não informado";
}

function entradaListaResumoCAICAVV(titulo, dados){
  const linhas = Object.entries(dados).sort((a,b)=>b[1]-a[1]).map(([nome,qtd])=>`<li><b>${entradaEscapeCAICAVV(nome)}:</b> ${qtd}</li>`).join("");
  return `<div class="entrada-box"><h3>${entradaEscapeCAICAVV(titulo)}</h3><ul class="entrada-resumo-lista">${linhas || "<li>Nenhum dado encontrado.</li>"}</ul></div>`;
}

function entradaFaixaEtariaCAICAVV(idade){
  const n = parseInt(idade,10);
  if(Number.isNaN(n)) return "Não informado";
  if(n <= 5) return "0 a 5 anos";
  if(n <= 11) return "6 a 11 anos";
  if(n <= 17) return "12 a 17 anos";
  return "18 anos ou mais";
}

function entradaMesNomeCAICAVV(valor){
  if(!valor) return "mês selecionado";
  const [ano, mes] = valor.split("-");
  const nomes = ["janeiro","fevereiro","março","abril","maio","junho","julho","agosto","setembro","outubro","novembro","dezembro"];
  return `${nomes[(parseInt(mes,10)||1)-1] || mes}/${ano}`;
}

function entradaUltimoDiaMesCAICAVV(mesAno){
  if(!mesAno || !/^\d{4}-\d{2}$/.test(mesAno)) return new Date().toISOString().slice(0,10);
  const [ano, mes] = mesAno.split("-").map(Number);
  return `${ano}-${String(mes).padStart(2,"0")}-${String(new Date(ano, mes, 0).getDate()).padStart(2,"0")}`;
}

function entradaDataISOCAICAVV(e){
  return String((e && (e.data || e.data_vinculacao)) || "").slice(0,10);
}

function entradaDataBRCAICAVV(valor){
  const data = String(valor || "").slice(0,10);
  if(!/^\d{4}-\d{2}-\d{2}$/.test(data)) return data || "não informado";
  const [ano, mes, dia] = data.split("-");
  return `${dia}/${mes}/${ano}`;
}

function entradaPeriodoLabelCAICAVV(){
  const inicio = document.getElementById("entradaDataInicio")?.value || "";
  const fim = document.getElementById("entradaDataFim")?.value || "";
  if(inicio && fim) return `${entradaDataBRCAICAVV(inicio)} até ${entradaDataBRCAICAVV(fim)}`;
  if(inicio) return `a partir de ${entradaDataBRCAICAVV(inicio)}`;
  if(fim) return `até ${entradaDataBRCAICAVV(fim)}`;
  return "todos os períodos";
}

function entradaPeriodoArquivoCAICAVV(){
  const inicio = document.getElementById("entradaDataInicio")?.value || "inicio";
  const fim = document.getElementById("entradaDataFim")?.value || "fim";
  return `${inicio}_a_${fim}`.replace(/[^0-9a-zA-Z_-]/g,"_");
}

function aplicarPeriodoEntradasCAICAVV(){
  const periodo = document.getElementById("entradaPeriodoRapido")?.value || "";
  const inicio = document.getElementById("entradaDataInicio");
  const fim = document.getElementById("entradaDataFim");
  if(!inicio || !fim) return;

  const anoBase = (inicio.value || fim.value || new Date().toISOString()).slice(0,4);
  const ano = /^\d{4}$/.test(anoBase) ? anoBase : String(new Date().getFullYear());

  const periodos = {
    "1tri": [`${ano}-01-01`, `${ano}-03-31`],
    "2tri": [`${ano}-04-01`, `${ano}-06-30`],
    "3tri": [`${ano}-07-01`, `${ano}-09-30`],
    "4tri": [`${ano}-10-01`, `${ano}-12-31`],
    "1sem": [`${ano}-01-01`, `${ano}-06-30`],
    "2sem": [`${ano}-07-01`, `${ano}-12-31`],
    "ano": [`${ano}-01-01`, `${ano}-12-31`]
  };

  if(periodos[periodo]){
    inicio.value = periodos[periodo][0];
    fim.value = periodos[periodo][1];
  }
  renderizarEntradasCAICAVV();
}

function entradasFiltradasPorPeriodoCAICAVV(){
  const dataInicio = document.getElementById("entradaDataInicio")?.value || "";
  const dataFim = document.getElementById("entradaDataFim")?.value || "";
  const busca = (document.getElementById("entradaBusca")?.value || "").toLowerCase().normalize("NFD").replace(/[̀-ͯ]/g, "");

  let lista = todasEntradasCAICAVV().filter(e => {
    const data = entradaDataISOCAICAVV(e);
    if(dataInicio && (!data || data < dataInicio)) return false;
    if(dataFim && (!data || data > dataFim)) return false;
    return true;
  });

  if(busca){
    lista = lista.filter(e => JSON.stringify(e).toLowerCase().normalize("NFD").replace(/[̀-ͯ]/g, "").includes(busca));
  }
  return lista;
}

