function adicionarEntradaCAICAVV(){
  if(!podeAlterarEntradasCAICAVV()){ mostrarErro ? mostrarErro("Somente Maiyara/coordenação pode alterar as entradas.") : alert("Somente Maiyara/coordenação pode alterar as entradas."); return; }
  const nova = {
    id: "manual-" + Date.now(),
    pasta: document.getElementById("entradaPasta")?.value.trim() || "",
    nome: document.getElementById("entradaNome")?.value.trim() || "",
    idade: document.getElementById("entradaIdade")?.value.trim() || "",
    sexo: document.getElementById("entradaSexo")?.value || "",
    bairro: document.getElementById("entradaBairro")?.value.trim() || "",
    origem: document.getElementById("entradaOrigem")?.value.trim() || "",
    violencia: document.getElementById("entradaViolencia")?.value.trim() || "",
    vinculacao: document.getElementById("entradaVinculacao")?.value.trim() || "",
    data: document.getElementById("entradaData")?.value || new Date().toISOString().slice(0,10),
    fonte: "Manual"
  };
  if(!nova.nome && !nova.pasta){ alert("Informe pelo menos o nome ou o nº da pasta."); return; }
  entradasManuaisCAICAVV.push(nova);
  salvarEntradasManuaisCAICAVV();
  renderizarEntradasCAICAVV();
}

function excluirEntradaCAICAVV(id){
  if(!podeAlterarEntradasCAICAVV()){ alert("Somente Maiyara/coordenação pode excluir entradas."); return; }
  if(!confirm("Excluir esta entrada manual?")) return;
  entradasManuaisCAICAVV = entradasManuaisCAICAVV.filter(e => String(e.id) !== String(id));
  salvarEntradasManuaisCAICAVV();
  renderizarEntradasCAICAVV();
}

function desenharGraficoEntradasCAICAVV(dados){
  const canvas = document.getElementById("graficoEntradasCAICAVV");
  if(!canvas) return;
  const ctx = canvas.getContext("2d");
  const w = canvas.width, h = canvas.height;
  ctx.clearRect(0,0,w,h);
  const itens = Object.entries(dados).sort((a,b)=>b[1]-a[1]).slice(0,8);
  ctx.font = "14px Arial";
  ctx.fillStyle = "#061852";
  if(!itens.length){ ctx.fillText("Sem dados para gerar gráfico.", 30, 45); return; }
  const max = Math.max(...itens.map(i=>i[1]));
  const margem = 42, largura = Math.max(42, (w - 90) / itens.length - 18);
  itens.forEach(([nome,qtd], i)=>{
    const x = margem + i * (largura + 18);
    const altura = Math.max(8, (qtd / max) * 170);
    const y = 215 - altura;
    ctx.fillStyle = getComputedStyle(document.body).getPropertyValue("--tema") || "#005bff";
    ctx.fillRect(x, y, largura, altura);
    ctx.fillStyle = "#061852";
    ctx.fillText(String(qtd), x + largura/2 - 5, y - 8);
    const rotulo = String(nome).slice(0,14);
    ctx.save();
    ctx.translate(x + 4, 242);
    ctx.rotate(-0.22);
    ctx.fillText(rotulo, 0, 0);
    ctx.restore();
  });
}

function importarEntradasCAICAVV(event){
  if(!podeAlterarEntradasCAICAVV()){ alert("Somente Maiyara/coordenação pode importar entradas."); event.target.value=""; return; }
  const arquivo = event.target.files && event.target.files[0];
  if(!arquivo) return;
  if(typeof XLSX === "undefined"){ alert("A biblioteca de importação ainda não carregou. Atualize a página e tente novamente."); return; }
  const leitor = new FileReader();
  leitor.onload = function(ev){
    const dados = new Uint8Array(ev.target.result);
    const wb = XLSX.read(dados, { type:"array" });
    const aba = wb.SheetNames[0];
    const linhas = XLSX.utils.sheet_to_json(wb.Sheets[aba], { defval:"" });
    linhas.forEach(linha => {
      const nova = normalizarEntradaImportadaCAICAVV(linha);
      if(nova.nome || nova.pasta) entradasManuaisCAICAVV.push(nova);
    });
    salvarEntradasManuaisCAICAVV();
    renderizarEntradasCAICAVV();
    alert("Importação concluída: " + linhas.length + " linhas lidas.");
  };
  leitor.readAsArrayBuffer(arquivo);
}

function normalizarEntradaImportadaCAICAVV(linha){
  const chaves = Object.keys(linha || {});
  const pegar = (...nomes) => {
    for(const nome of nomes){
      const achada = chaves.find(c => String(c).toLowerCase().normalize("NFD").replace(/[̀-ͯ]/g,"").includes(String(nome).toLowerCase().normalize("NFD").replace(/[̀-ͯ]/g,"")));
      if(achada) return linha[achada];
    }
    return "";
  };
  return {
    id: "manual-" + Date.now() + "-" + Math.random().toString(36).slice(2),
    pasta: String(pegar("pasta","nº","numero","número") || "").trim(),
    nome: String(pegar("nome","criança","crianca","paciente") || "").trim(),
    idade: String(pegar("idade") || "").trim(),
    sexo: String(pegar("sexo") || "").trim(),
    bairro: String(pegar("bairro") || "").trim(),
    origem: String(pegar("origem","encaminhado","encaminhamento") || "").trim(),
    violencia: String(pegar("violência","violencia","violação","violacao","tipo") || "").trim(),
    vinculacao: String(pegar("vinculação","vinculacao","status","vínculo","vinculo") || "").trim(),
    data: formatarDataEntradaCAICAVV(pegar("data vinculação","data vinculacao","data","entrada")) || new Date().toISOString().slice(0,10),
    fonte: "Importado"
  };
}

function formatarDataEntradaCAICAVV(valor){
  if(!valor) return "";
  if(typeof XLSX !== "undefined" && typeof valor === "number"){
    const d = XLSX.SSF.parse_date_code(valor);
    if(d) return `${d.y}-${String(d.m).padStart(2,"0")}-${String(d.d).padStart(2,"0")}`;
  }
  const texto = String(valor).trim();
  if(/^\d{4}-\d{2}-\d{2}/.test(texto)) return texto.slice(0,10);
  if(texto.includes("/")){
    const [dia,mes,ano] = texto.split("/");
    if(ano) return `${ano.padStart(4,"20")}-${mes.padStart(2,"0")}-${dia.padStart(2,"0")}`;
  }
  return "";
}


