      '<div class="upload-grid-caicavv">'+
        '<div class="upload-card-caicavv"><h3>1. Upload de agendamentos passados</h3><p>Envie uma planilha .ods, .xlsx ou .xls, escolha a aba e gere uma prévia antes de salvar.</p>'+
          '<label>Arquivo</label><input id="uploadArquivoPlanilha" type="file" accept=".ods,.xlsx,.xls" onchange="lerArquivoUploadPlanilhaCAICAVV(event)">'+
          '<label>Aba da planilha</label><select id="uploadNomeAba" onchange="prepararUploadPlanilhaCAICAVV()"><option value="">Envie um arquivo primeiro</option></select>'+
          '<label>Nome do relatório/importação</label><input id="uploadNomeRelatorio" placeholder="Ex: Janeiro 2026 - Cláudia">'+
          '<label>Técnico</label><select id="uploadTecnico">'+montarOptionsTecnicosUpload()+ '</select>'+
          '<button type="button" class="secundario" onclick="prepararUploadPlanilhaCAICAVV()">Gerar prévia</button>'+
          '<button type="button" id="btnImportarUpload" onclick="importarUploadPlanilhaFirebaseCAICAVV()" disabled>Importar para relatório</button>'+
          '<div class="upload-aviso-caicavv">O leitor procura automaticamente as colunas <b>DATA</b>, <b>PASTA</b>, <b>COMPARECEU</b>, <b>NÃO COMPARECEU</b> e <b>OBSERVAÇÃO</b>.</div></div>'+
        '<div class="upload-card-caicavv"><h3>2. Resumo</h3><p id="uploadResumoTexto">Nenhuma planilha lida ainda.</p><div id="uploadResumoCards" class="upload-resumo-caicavv"></div></div>'+
      '</div>'+
      '<div class="upload-card-caicavv" style="margin-top:14px"><h3>Prévia dos agendamentos</h3><div id="uploadPreview" class="upload-aviso-caicavv">A prévia aparecerá aqui depois da leitura.</div></div>'+
      '<div class="upload-card-caicavv upload-entradas-area"><h3>Upload do arquivo de entradas</h3><p>Use aqui para importar o arquivo de entradas sem precisar abrir a aba Entradas.</p>'+
        '<label>Arquivo de entradas</label><input id="uploadEntradasArquivo" type="file" accept=".ods,.xlsx,.xls" onchange="lerArquivoEntradasUploadCAICAVV(event)">'+
        '<label>Aba da planilha</label><select id="uploadEntradasAba" onchange="prepararEntradasUploadCAICAVV()"><option value="">Envie um arquivo primeiro</option></select>'+
        '<button type="button" class="secundario" onclick="prepararEntradasUploadCAICAVV()">Gerar prévia de entradas</button>'+
        '<button type="button" id="btnImportarEntradasUpload" onclick="importarEntradasUploadCAICAVV()" disabled>Importar entradas</button>'+
        '<div id="uploadEntradasPreview" class="upload-aviso-caicavv">A prévia das entradas aparecerá aqui.</div></div>'+
      '<div class="upload-card-caicavv" style="margin-top:14px"><h3>Uploads importados</h3><p>As importações salvas aparecem aqui em formato de pasta, com os atendimentos da planilha e resumo final.</p><div id="uploadPastasImportadas"></div></div>';
    renderizarPastasUploadImportadasCAICAVV();
    garantirRelatoriosUploadCAICAVV().then(function(){ renderizarPastasUploadImportadasCAICAVV(); }).catch(function(e){ console.error(e); renderizarPastasUploadImportadasCAICAVV(); });
